    "id": "heward-s-handy-haversack",
    "slug": "heward-s-handy-haversack",
    "nome": "Sacca a Tracolla Manesca di Heward",
    "nome_en": "Heward's Handy Haversack",
    "tipo": "Oggetto Meraviglioso",
